#### Model Solution to Question B(b):

```dart
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:flutter/material.dart';

class CreatePostScreen extends StatefulWidget {
  const CreatePostScreen({super.key});

  @override
  State<CreatePostScreen> createState() => _CreatePostScreenState();
}

class _CreatePostScreenState extends State<CreatePostScreen> {
  final TextEditingController _titleController = TextEditingController();
  final TextEditingController _bodyController = TextEditingController();
  bool _isLoading = false;
  String? _responseMessage;

  // Step 1: Function to perform the POST request
  Future<void> createPost() async {
    setState(() {
      _isLoading = true;
      _responseMessage = null;
    });

    try {
      // Step 2: Build the URI
      final uri = Uri.parse('https://jsonplaceholder.typicode.com/posts');

      // Step 3: Construct the request body as a JSON map, then encode
      final Map<String, dynamic> body = {
        'title': _titleController.text,
        'body': _bodyController.text,
        'userId': 1,
      };

      // Step 4: Send the POST request
      final response = await http.post(
        uri,
        headers: {
          'Content-Type': 'application/json; charset=UTF-8',
        },
        body: jsonEncode(body),
      );

      // Step 5: Handle the response based on status code
      if (response.statusCode == 201) {
        // 201 Created — success
        final createdPost = jsonDecode(response.body);
        setState(() {
          _responseMessage = '✅ Post created! ID: ${createdPost['id']}';
        });
      } else {
        // Non-success status
        setState(() {
          _responseMessage = '❌ Server returned ${response.statusCode}';
        });
      }
    } catch (e) {
      // Network or parsing error
      setState(() {
        _responseMessage = '❌ Error: $e';
      });
    } finally {
      setState(() {
        _isLoading = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Create Post')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          children: [
            TextField(
              controller: _titleController,
              decoration: const InputDecoration(labelText: 'Title'),
            ),
            TextField(
              controller: _bodyController,
              decoration: const InputDecoration(labelText: 'Body'),
              maxLines: 3,
            ),
            const SizedBox(height: 16),
            _isLoading
                ? const CircularProgressIndicator()
                : ElevatedButton(
                    onPressed: createPost,
                    child: const Text('Submit'),
                  ),
            const SizedBox(height: 16),
            if (_responseMessage != null)
              Text(_responseMessage!),
          ],
        ),
      ),
    );
  }
}
```

**Step-by-step explanation:**

1. **Import the packages** — `http` for network calls, `dart:convert` for JSON encoding.
2. **Build the URL** using `Uri.parse()` (a `String` is **not** accepted by `http.post`).
3. **Construct the body** as a `Map<String, dynamic>`, then `jsonEncode()` converts it to a JSON string.
4. **Set headers** — `'Content-Type': 'application/json'` tells the server the body format.
5. **Send the POST request** with `await http.post(...)`. The function is `async` so the UI remains responsive.
6. **Validate the response** — `201 Created` is the standard success code for `POST`. (Note: `200 OK` is also acceptable in some APIs.)
7. **Use try/catch/finally** to handle:
   - **try**: The actual request and response logic.
   - **catch (e)`: Network errors (`SocketException`), timeouts, or JSON parsing errors.
   - **finally**: Always reset `_isLoading` to `false` so the UI regains interactivity.

